CREATE OR REPLACE FUNCTION fpb_get_keep_amount_real (as_memno char, ai_year bigint,ai_month bigint,ai_seq bigint) RETURNS bigint AS $body$
DECLARE

  ldc_principal decimal(15,2);

BEGIN
  select sum(money_amount) into STRICT ldc_principal
  from sc_kep_t_monthly_receive_det
  where (membership_no = as_memno)
  and (receive_year = ai_year)
  and (receive_month = ai_month)
  and (seq_no = ai_seq)
  and trim(both loan_type) <> 'SH';

  if coalesce(ldc_principal::text, '') = '' then ldc_principal := 0;end if;
  return ldc_principal;

exception
when too_many_rows then return null;
when no_data_found then return null;
when others then CALL spa_dberror('fpa_get_kep_method_ref,'||as_memno||'');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
